#include <IRremote.h>
#include <ArduinoJson.h>
#include <EEPROM.h>

// IR Configuration
#define IR_RECEIVER_PIN {{.irReceiverPin}}
#define ENABLE_LEARNING {{.enableLearning}}
#define AUTO_OFF_DELAY {{.autoOffDelay}} // minutes, 0 = disabled

// Relay Configuration
const int relayPins[4] = {{.relay1Pin}, {{.relay2Pin}}, {{.relay3Pin}}, {{.relay4Pin}};

// Status Configuration
#define STATUS_LED_PIN {{.ledPin}}
#define BUZZER_PIN {{.buzzerPin}}
const char* deviceName = "{{.deviceName}}";

// EEPROM Configuration
#define EEPROM_SIZE 512
#define REMOTE_COUNT_ADDR 0
#define COMMAND_COUNT_BASE_ADDR 100
#define REMOTE_NAME_BASE_ADDR 200
#define COMMAND_DATA_BASE_ADDR 300

// Maximum configurations
#define MAX_REMOTES 10
#define MAX_COMMANDS_PER_REMOTE 20

// Global variables
IRrecv irrecv(IR_RECEIVER_PIN);
decode_results_t results;

// Remote storage
struct RemoteInfo {
  uint32_t hash;
  char name[32];
  int commandCount;
  uint32_t commandHashes[MAX_COMMANDS_PER_REMOTE];
};

RemoteInfo remotes[MAX_REMOTES];
int remoteCount = 0;

// Command storage
struct CommandInfo {
  uint32_t hash;
  uint8_t relayMask; // Bitmask for which relays to control
  bool toggle; // true=toggle, false=set state
  uint32_t autoOffDelay; // Auto-off delay in minutes (0=disabled)
};

CommandInfo commands[MAX_REMOTES * MAX_COMMANDS_PER_REMOTE];

// System state
bool learningMode = false;
unsigned long lastCommandTime = 0;
unsigned long autoOffTimers[4] = {0, 0, 0, 0};
bool relayStates[4] = {false, false, false, false};
bool systemArmed = true;

// Function prototypes
void setupIR();
void loadConfiguration();
void saveConfiguration();
void processIRCommand(uint32_t hash);
void executeCommand(CommandInfo command);
void updateRelays();
void updateStatusLED();
void beep(int duration);
void startLearningMode();
void stopLearningMode();
uint32_t calculateHash(decode_results_t *results);
String getRemoteName(uint32_t hash);
void printStatus();
void handleAutoOff();

void setup() {
  Serial.begin(115200);
  Serial.println("IR Remote Control for Appliance Automation Starting...");

  // Initialize pins
  pinMode(STATUS_LED_PIN, OUTPUT);
  if (BUZZER_PIN > 0) {
    pinMode(BUZZER_PIN, OUTPUT);
  }

  for (int i = 0; i < 4; i++) {
    pinMode(relayPins[i], OUTPUT);
    digitalWrite(relayPins[i], HIGH); // Relays are active LOW
  }

  digitalWrite(STATUS_LED_PIN, LOW);
  if (BUZZER_PIN > 0) {
    digitalWrite(BUZZER_PIN, LOW);
  }

  // Initialize IR receiver
  setupIR();

  // Load configuration from EEPROM
  loadConfiguration();

  Serial.print("Configuration loaded - ");
  Serial.print(remoteCount);
  Serial.println(" remotes, ");
  int totalCommands = 0;
  for (int i = 0; i < remoteCount; i++) {
    totalCommands += remotes[i].commandCount;
  }
  Serial.print(totalCommands);
  Serial.println(" commands");

  // Initial status
  updateStatusLED();
  printStatus();

  Serial.println("Setup completed!");
  Serial.println("Commands:");
  Serial.println("  - Press button to execute command");
  Serial.println("  - Hold button 3 seconds to enter learning mode");
  Serial.println("  - Send 'HELP' for command list");
}

void setupIR() {
  irrecv.enableIRIn();
  irrecv.blink13(true); // Enable LED feedback
  Serial.println("IR receiver initialized");
}

void loadConfiguration() {
  EEPROM.begin(EEPROM_SIZE);

  // Load remote count
  remoteCount = EEPROM.read(REMOTE_COUNT_ADDR);
  if (remoteCount > MAX_REMOTES) {
    remoteCount = MAX_REMOTES;
  }

  // Load remote information
  for (int i = 0; i < remoteCount; i++) {
    EEPROM.get(REMOTE_NAME_BASE_ADDR + (i * 32), remotes[i].name, 32);

    // Read remote hash
    for (int j = 0; j < 4; j++) {
      ((byte*)&remotes[i].hash)[j] = EEPROM.read(REMOTE_NAME_BASE_ADDR + (i * 32) + 32 + (j * 4));
    }

    // Load command count
    remotes[i].commandCount = EEPROM.read(COMMAND_COUNT_BASE_ADDR + i);
    if (remotes[i].commandCount > MAX_COMMANDS_PER_REMOTE) {
      remotes[i].commandCount = MAX_COMMANDS_PER_REMOTE;
    }

    // Load command information
    for (int j = 0; j < remotes[i].commandCount; j++) {
      CommandInfo cmd;

      // Read command hash
      for (int k = 0; k < 4; k++) {
        ((byte*)&cmd.hash)[k] = EEPROM.read(COMMAND_DATA_BASE_ADDR + (i * MAX_COMMANDS_PER_REMOTE * 12) + (j * 12) + (k * 4));
      }

      // Read relay mask
      cmd.relayMask = EEPROM.read(COMMAND_DATA_BASE_ADDR + (i * MAX_COMMANDS_PER_REMOTE * 12) + (j * 12) + 8);

      // Read toggle flag
      cmd.toggle = EEPROM.read(COMMAND_DATA_BASE_ADDR + (i * MAX_COMMANDS_PER_REMOTE * 12) + (j * 12) + 9);

      // Read auto-off delay
      for (int k = 0; k < 4; k++) {
        ((byte*)&cmd.autoOffDelay)[k] = EEPROM.read(COMMAND_DATA_BASE_ADDR + (i * MAX_COMMANDS_PER_REMOTE * 12) + (j * 12) + 10 + (k * 4));
      }

      commands[i * MAX_COMMANDS_PER_REMOTE + j] = cmd;
    }
  }

  // Load remote names
  for (int i = 0; i < remoteCount; i++) {
    EEPROM.get(REMOTE_NAME_BASE_ADDR + (i * 32), remotes[i].name, 32);
  }
}

void saveConfiguration() {
  EEPROM.put(REMOTE_COUNT_ADDR, remoteCount);

  // Save remote information
  for (int i = 0; i < remoteCount; i++) {
    EEPROM.put(REMOTE_NAME_BASE_ADDR + (i * 32), remotes[i].name, 32);

    // Save remote hash
    for (int j = 0; j < 4; j++) {
      EEPROM.put(REMOTE_NAME_BASE_ADDR + (i * 32) + 32 + (j * 4), ((byte*)&remotes[i].hash)[j]);
    }

    // Save command count
    EEPROM.put(COMMAND_COUNT_BASE_ADDR + i, remotes[i].commandCount);

    // Save command information
    for (int j = 0; j < remotes[i].commandCount; j++) {
      CommandInfo cmd = commands[i * MAX_COMMANDS_PER_REMOTE + j];

      // Save command hash
      for (int k = 0; k < 4; k++) {
        EEPROM.put(COMMAND_DATA_BASE_ADDR + (i * MAX_COMMANDS_PER_REMOTE * 12) + (j * 12) + (k * 4), ((byte*)&cmd.hash)[k]);
      }

      // Save relay mask
      EEPROM.put(COMMAND_DATA_BASE_ADDR + (i * MAX_COMMANDS_PER_REMOTE * 12) + (j * 12) + 8, cmd.relayMask);

      // Save toggle flag
      EEPROM.put(COMMAND_DATA_BASE_ADDR + (i * MAX_COMMANDS_PER_REMOTE * 12) + (j * 12) + 9, cmd.toggle);

      // Save auto-off delay
      for (int k = 0; k < 4; k++) {
        EEPROM.put(COMMAND_DATA_BASE_ADDR + (i * MAX_COMMANDS_PER_REMOTE * 12) + (j * 12) + 10 + (k * 4), ((byte*)&cmd.autoOffDelay)[k]);
      }
    }
  }

  EEPROM.commit();
  Serial.println("Configuration saved to EEPROM");
}

void loop() {
  if (irrecv.decode(&results)) {
    if (results.value) {
      uint32_t hash = calculateHash(&results);

      if (learningMode) {
        // In learning mode, store the new command
        storeCommand(hash);
      } else {
        // In normal mode, execute the command
        processIRCommand(hash);
      }

      lastCommandTime = millis();
      updateStatusLED();
    }
  }

  // Handle learning mode timeout
  static unsigned long learningStartTime = 0;
  if (learningMode && millis() - learningStartTime > 10000) {
    Serial.println("Learning mode timeout");
    stopLearningMode();
  }

  // Handle auto-off timers
  handleAutoOff();

  // Status LED blink
  static unsigned long lastBlinkTime = 0;
  if (millis() - lastBlinkTime >= 2000) {
    digitalWrite(STATUS_LED_PIN, !digitalRead(STATUS_LED_PIN));
    lastBlinkTime = millis();
  }

  delay(100);
}

void processIRCommand(uint32_t hash) {
  // Find matching command
  for (int i = 0; i < remoteCount; i++) {
    if (remotes[i].hash == hash) {
      for (int j = 0; j < remotes[i].commandCount; j++) {
        if (commands[i * MAX_COMMANDS_PER_REMOTE + j].hash == hash) {
          executeCommand(commands[i * MAX_COMMANDS_PER_REMOTE + j]);
          return;
        }
      }
    }
  }

  Serial.print("Unknown command hash: 0x");
  Serial.print(hash, HEX);
  Serial.println();
  beep(100); // Error beep
}

void executeCommand(CommandInfo command) {
  Serial.print("Executing command from ");
  Serial.print(getRemoteName(command.hash));
  Serial.print(": ");

  // Update relay states
  for (int i = 0; i < 4; i++) {
    if (command.relayMask & (1 << i)) {
      if (command.toggle) {
        relayStates[i] = !relayStates[i];
      } else {
        relayStates[i] = true;
        // Set auto-off timer if specified
        if (command.autoOffDelay > 0) {
          autoOffTimers[i] = millis() + (command.autoOffDelay * 60000UL);
        }
      }
    }
  }

  updateRelays();

  Serial.print("Relays activated: ");
  for (int i = 0; i < 4; i++) {
    if (relayStates[i]) {
      Serial.print("R");
      Serial.print(i + 1);
    }
  }
  Serial.println();

  beep(200); // Success beep
}

void updateRelays() {
  for (int i = 0; i < 4; i++) {
    // Relays are active LOW
    digitalWrite(relayPins[i], relayStates[i] ? LOW : HIGH);
  }
}

void updateStatusLED() {
  if (learningMode) {
    // Fast blink during learning mode
    static unsigned long lastBlinkTime = 0;
    if (millis() - lastBlinkTime >= 200) {
      digitalWrite(STATUS_LED_PIN, !digitalRead(STATUS_LED_PIN));
      lastBlinkTime = millis();
    }
  } else if (systemArmed) {
    // Slow blink when armed
    static unsigned long lastBlinkTime = 0;
    if (millis() - lastBlinkTime >= 2000) {
      digitalWrite(STATUS_LED_PIN, !digitalRead(STATUS_LED_PIN));
      lastBlinkTime = millis();
    }
  } else {
    // Solid when disarmed
    digitalWrite(LED_PIN, HIGH);
  }
}

void beep(int duration) {
  if (BUZZER_PIN > 0) {
    digitalWrite(BUZZER_PIN, HIGH);
    delay(duration);
    digitalWrite(BUZZER_PIN, LOW);
  }
}

void startLearningMode() {
  learningMode = true;
  Serial.println("Learning mode started");
  Serial.println("Point remote at receiver and press button to learn");
  Serial.println("Timeout: 10 seconds");

  beep(1000); // Long beep to indicate learning mode
  updateStatusLED();

  learningStartTime = millis();
}

void stopLearningMode() {
  learningMode = false;
  Serial.println("Learning mode stopped");

  saveConfiguration();
  beep(500); // Confirmation beep
  updateStatusLED();
}

void storeCommand(uint32_t hash) {
  // Check if we have space for a new remote
  if (remoteCount >= MAX_REMOTES) {
    Serial.println("Maximum remotes reached");
    return;
  }

  // Find if this is a new remote or existing one
  int remoteIndex = -1;
  for (int i = 0; i < remoteCount; i++) {
    if (remotes[i].hash == hash) {
      remoteIndex = i;
      break;
    }
  }

  // If new remote, add it
  if (remoteIndex == -1) {
    remoteIndex = remoteCount++;
    remotes[remoteIndex].hash = hash;
    sprintf(remotes[remoteIndex].name, "Remote %d", remoteIndex + 1);
    remotes[remoteIndex].commandCount = 0;

    Serial.print("New remote learned: ");
    Serial.println(remotes[remoteIndex].name);
  }

  // Add command to remote
  if (remotes[remoteIndex].commandCount < MAX_COMMANDS_PER_REMOTE) {
    int cmdIndex = remotes[remoteIndex].commandCount++;
    CommandInfo cmd;
    cmd.hash = hash;
    cmd.relayMask = 0; // No relays by default
    cmd.toggle = true; // Default to toggle
    cmd.autoOffDelay = 0; // No auto-off by default

    commands[remoteIndex * MAX_COMMANDS_PER_REMOTE + cmdIndex] = cmd;
    remotes[remoteIndex].commandCount++;

    Serial.print("Command learned for ");
    Serial.print(remotes[remoteIndex].name);
    Serial.print(": Command ");
    Serial.print(cmdIndex + 1);
    Serial.println();
  }

  beep(300); // Success beep
}

uint32_t calculateHash(decode_results_t *results) {
  uint32_t hash = 0;
  hash = ((uint32_t)results->value);
  hash |= ((uint32_t)results->decode_type) << 24;
  hash |= ((uint32_t)results->address) << 16;
  hash |= ((uint32_t)results->command) << 8;
  hash |= ((uint32_t)results->reserved);
  return hash;
}

String getRemoteName(uint32_t hash) {
  for (int i = 0; i < remoteCount; i++) {
    if (remotes[i].hash == hash) {
      return String(remotes[i].name);
    }
  }
  return "Unknown";
}

void printStatus() {
  Serial.println("=== Status ===");
  Serial.print("Device: ");
  Serial.println(deviceName);
  Serial.print("Mode: ");
  Serial.println(learningMode ? "Learning" : "Normal");
  Serial.print("Remotes: ");
  Serial.println(remoteCount);

  Serial.println("\nRelay States:");
  for (i = 0; i < 4; i++) {
    Serial.print("  Relay ");
    Serial.print(i + 1);
    Serial.print(": ");
    Serial.println(relayStates[i] ? "ON" : "OFF");
  }

  Serial.println("\nAuto-Off Timers:");
  for (int i = 0; i < 4; i++) {
    if (autoOffTimers[i] > 0) {
      int remaining = (autoOffTimers[i] - millis()) / 60000;
      Serial.print("  Relay ");
      Serial.print(i + 1);
      Serial.print(": ");
      Serial.print(remaining);
      Serial.println(" minutes remaining");
    }
  }

  Serial.println("\nCommands in last 5 minutes:");
  if (millis() - lastCommandTime < 300000) {
    Serial.println("  Recent: ");
    Serial.print(getRemoteName(lastCommandHash));
  } else {
    Serial.println("  No recent commands");
  }
  Serial.println("================\n");
}

void handleAutoOff() {
  unsigned long currentTime = millis();

  for (int i = 0; i < 4; i++) {
    if (autoOffTimers[i] > 0 && currentTime >= autoOffTimers[i]) {
      Serial.print("Auto-off: Relay ");
      Serial.print(i + 1);
      Serial.println(" turned off automatically");

      relayStates[i] = false;
      autoOffTimers[i] = 0;
      updateRelays();
      updateStatusLED();
      beep(100); // Notification beep
    }
  }
}

// Helper function to print help information
void printHelp() {
  Serial.println("=== Help ===");
  Serial.println("Commands:");
  Serial.println("  HELP - Show this help message");

  if (remoteCount > 0) {
    Serial.println("\nLearned Remotes:");
    for (i = 0; i < remoteCount; i++) {
      Serial.print("  ");
      Serial.print(i + 1);
      Serial.print(": ");
      Serial.println(remotes[i].name);

      Serial.print("    Commands: ");
      for (j = 0; j < remotes[i].commandCount; j++) {
        CommandInfo cmd = commands[i * MAX_COMMANDS_PER_REMOTE + j];
        Serial.print(j + 1);
        Serial.print(": ");
        Serial.print(cmd.relayMask, BIN);
        Serial.print(");
        Serial.println(cmd.toggle ? "(toggle)" : "(set)");
      }
    }
  }

  Serial.println("\nSystem Commands:");
  Serial.println("  LEARN - Enter learning mode");

  if (learningMode) {
    Serial.println("  EXIT - Exit learning mode");
  }

  Serial.println("  STATUS - Show system status");
  Serial.println("  CLEAR - Turn off all relays");
  Serial.println("================\n");
}

// Serial command handler for HELP command
void handleSerialCommand(String command) {
  command.toUpperCase();

  if (command == "HELP") {
    printHelp();
  } else if (command == "LEARN") {
    startLearningMode();
  } else if (command == "EXIT") {
    stopLearningMode();
  } else if (command == "STATUS") {
    printStatus();
  } else if (command == "CLEAR") {
    // Turn off all relays
    for (int i = 0; i < 4; i++) {
      relayStates[i] = false;
      autoOffTimers[i] = 0;
    }
    updateRelays();
    updateStatusLED();
    Serial.println("All relays turned off");
  } else {
    Serial.print("Unknown command: ");
    Serial.println(command);
  }
}

// Serial input handler
void serialEvent() {
  if (Serial.available()) {
    String command = Serial.readStringUntil('\n');
    handleSerialCommand(command);
  }
}
